using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves HttpClient and ILogger
/// from DI and does NOT expose them in the tool schema.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all resources from the API. Returns a JSON array.")]
    public async Task<string> ListResources(
        [Description("Maximum number of items to return (1-100)")] int limit = 20,
        [Description("Page number for pagination (starts at 1)")] int page = 1,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing resources (limit={Limit}, page={Page})", limit, page);
        var response = await httpClient.GetAsync($"/resources?limit={limit}&page={page}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get a single resource by its unique identifier.")]
    public async Task<string> GetResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting resource {Id}", id);
        var response = await httpClient.GetAsync($"/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = false, ReadOnly = false),
     Description("Create a new resource with the given name and description.")]
    public async Task<string> CreateResource(
        [Description("Name for the new resource")] string name,
        [Description("Optional description of the resource")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating resource {Name}", name);
        var payload = JsonSerializer.Serialize(new { name, description }, JsonOptions);
        var content = new StringContent(payload, Encoding.UTF8, "application/json");

        var response = await httpClient.PostAsync("/resources", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Destructive = true), Description("Delete a resource by its unique identifier.")]
    public async Task<string> DeleteResource(
        [Description("The unique identifier of the resource to delete")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Deleting resource {Id}", id);
        var response = await httpClient.DeleteAsync($"/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return $"Resource {id} deleted successfully.";
    }

    [McpServerTool(ReadOnly = true), Description("Search resources by a query string.")]
    public async Task<string> SearchResources(
        [Description("Search query to match against resource names and descriptions")] string query,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources for '{Query}'", query);
        var encoded = Uri.EscapeDataString(query);
        var response = await httpClient.GetAsync($"/resources/search?q={encoded}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

